/**
 * LangSmith tracing configuration loader with centralized configuration integration
 * NOW INTEGRATED WITH THE CENTRALIZED CONFIGURATION SYSTEM
 * 
 * @deprecated Use configManager from ../config/index.js instead for new code
 * This file maintained for backward compatibility
 */

import { getEnvVar, getEnvVarWithDefault } from '../utils/env.js';
import { configManager, getConfiguration } from './index.js';

export interface TracingConfig {
  enabled: boolean;
  apiKey?: string;
  project?: string;
  endpoint?: string;
  sessionName?: string;
  tags: string[];
  samplingRate: number;
}

/**
 * Load tracing configuration from centralized configuration system
 * Falls back to legacy environment loading if centralized config not available
 */
export function loadTracingConfig(): TracingConfig {
  try {
    // Try to use centralized configuration first
    const config = getConfiguration();
    return {
      enabled: config.tracing.enabled,
      apiKey: config.tracing.apiKey,
      project: config.tracing.project,
      endpoint: config.tracing.endpoint,
      sessionName: config.tracing.sessionName,
      tags: config.tracing.tags,
      samplingRate: config.tracing.samplingRate,
    };
  } catch {
    // Fallback to legacy environment loading - check both standard and custom names
    console.warn('WARNING: Using legacy tracing configuration loading - consider using configManager.load() first');
    const config: TracingConfig = {
      enabled: getEnvVar('LANGCHAIN_TRACING_V2') === 'true' || getEnvVar('LANGSMITH_TRACING') === 'true',
      apiKey: getEnvVar('LANGCHAIN_API_KEY') || getEnvVar('LANGSMITH_API_KEY'),
      project: getEnvVarWithDefault('LANGCHAIN_PROJECT', null) || getEnvVarWithDefault('LANGSMITH_PROJECT', 'konnect-mcp-server'),
      endpoint: getEnvVarWithDefault('LANGCHAIN_ENDPOINT', null) || getEnvVarWithDefault('LANGSMITH_ENDPOINT', 'https://api.smith.langchain.com'),
      sessionName: getEnvVarWithDefault('LANGSMITH_SESSION', 'mcp-session'),
      tags: getEnvVar('LANGSMITH_TAGS')?.split(',') || ['mcp-server', 'kong-konnect'],
      samplingRate: parseFloat(getEnvVarWithDefault('LANGSMITH_SAMPLING_RATE', '1.0')),
    };

    return config;
  }
}

/**
 * Initialize environment loading for Node.js compatibility
 * Bun loads .env files automatically, but Node.js needs explicit loading
 * 
 * @deprecated Use initializeEnvironment from utils/env.ts instead
 */
export async function initializeEnvironment(): Promise<void> {
  // Delegate to centralized environment utility
  const { initializeEnvironment: initEnv } = await import('../utils/env.js');
  return await initEnv();
}

/**
 * Validate that tracing configuration is properly set
 * @deprecated Use configManager.getHealth() instead for comprehensive validation
 */
export function validateTracingConfig(config: TracingConfig): { isValid: boolean; errors: string[] } {
  const errors: string[] = [];

  if (config.enabled) {
    if (!config.apiKey || config.apiKey.trim() === '') {
      errors.push('LANGSMITH_API_KEY is required when tracing is enabled');
    }

    if (!config.project || config.project.trim() === '') {
      errors.push('LANGSMITH_PROJECT is required when tracing is enabled');
    }

    if (config.samplingRate < 0 || config.samplingRate > 1) {
      errors.push('LANGSMITH_SAMPLING_RATE must be between 0.0 and 1.0');
    }

    // Validate API key format (LangSmith keys typically start with 'lsv2_')
    if (config.apiKey && !config.apiKey.startsWith('lsv2_')) {
      console.warn('Warning: LangSmith API key may not be in correct format (should start with lsv2_)');
    }
  }

  return {
    isValid: errors.length === 0,
    errors
  };
}

/**
 * Get tracing configuration from centralized system
 * This is the recommended way to get tracing configuration in new code
 */
export async function getTracingConfig(): Promise<TracingConfig> {
  try {
    const config = await configManager.load();
    return {
      enabled: config.tracing.enabled,
      apiKey: config.tracing.apiKey,
      project: config.tracing.project,
      endpoint: config.tracing.endpoint,
      sessionName: config.tracing.sessionName,
      tags: config.tracing.tags,
      samplingRate: config.tracing.samplingRate,
    };
  } catch (error) {
    console.error('Failed to load tracing configuration from centralized system:', error);
    throw error;
  }
}

/**
 * Get runtime information for debugging
 * 
 * @deprecated Use getRuntimeInfo from utils/env.ts instead
 */
export async function getRuntimeInfo(): Promise<{
  runtime: 'bun' | 'node' | 'unknown';
  version: string;
  envSource: 'Bun.env' | 'process.env';
  autoEnvLoading: boolean;
}> {
  // Delegate to centralized environment utility
  const envModule = await import('../utils/env.js');
  const { getRuntimeInfo: getRuntimeInfoFromEnv } = envModule;
  return getRuntimeInfoFromEnv();
}